1	const PROCESSING_FEE_G = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PRICE_G = 60;
4	const COMPONENT_UNIT_PRICE_G = 25;
5	
6	const MAIN_ITEM_BASE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
13	
14	type Item = { type: string; cursed?: boolean };
15	type Scenario = {
16	  customer: { yearsWithMHPCO: number };
17	  steps: Array<{ op: "quote"; items: Item[] }>;
18	};
19	
20	const sum = (numbers: number[]): number =>
21	  numbers.reduce((acc, n) => acc + n, 0);
22	
23	const componentBaseForGroup = (count: number): number =>
24	  count === BLOCK_SIZE ? BLOCK_PRICE_G : count * COMPONENT_UNIT_PRICE_G;
25	
26	const componentBaseTotal = (componentItems: Item[]): number => {
27	  const counts = new Map<string, number>();
28	  for (const item of componentItems) {
29	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
30	  }
31	  return sum([...counts.values()].map(componentBaseForGroup));
32	};
33	
34	const mainItemBase = (item: Item): number => MAIN_ITEM_BASE[item.type] ?? 0;
35	
36	const mainItemModifiers = (item: Item): number =>
37	  item.cursed ? mainItemBase(item) * 0.5 : 0;
38	
39	const firstInsuranceSurcharge = (policyBase: number): number => policyBase / 10;
40	
41	const loyaltyDiscount = (policyBase: number, yearsWithMHPCO: number): number =>
42	  yearsWithMHPCO >= 2 ? policyBase * 0.2 : 0;
43	
44	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
45	
46	const quotePremium = (items: Item[], yearsWithMHPCO: number): number => {
47	  const mainItems = items.filter((i) => !isComponent(i));
48	  const componentItems = items.filter(isComponent);
49	  const policyBase = sum(mainItems.map(mainItemBase)) + componentBaseTotal(componentItems);
50	  const itemModifiersTotal = sum(mainItems.map(mainItemModifiers));
51	  const surcharges = firstInsuranceSurcharge(policyBase);
52	  const discounts = loyaltyDiscount(policyBase, yearsWithMHPCO);
53	  return Math.ceil(policyBase + itemModifiersTotal + surcharges - discounts + PROCESSING_FEE_G);
54	};
55	
56	export const runScenario = (scenario: unknown): unknown => {
57	  const s = scenario as Scenario;
58	  const items = s.steps[0].items;
59	  return { results: [{ premium: quotePremium(items, s.customer.yearsWithMHPCO) }] };
60	};
